def recommend_computing_paradigm(problem_type):
    problem_lower = problem_type.lower()

    quantum_keywords = ['factoring', 'search', 'simulation', 'optimization', 'molecule', 'quantum']
    classical_keywords = ['sorting', 'web', 'word', 'file', 'graphics', 'editing', 'document']

    for kw in quantum_keywords:
        if kw in problem_lower:
            return 'quantum', f'Known quantum advantage for {kw} problems'

    for kw in classical_keywords:
        if kw in problem_lower:
            return 'classical', f'Classical computers excel at {kw} tasks'

    return 'hybrid', 'May benefit from hybrid approach'

problems = ['factoring large numbers', 'sorting a list', 'simulating molecules', 'editing documents']
for p in problems:
    rec, reason = recommend_computing_paradigm(p)
    print(f'{p}: {rec}')
    print(f'  Reason: {reason}\n')
